arguments.file_text:
@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Project Board</h1>

@if (_loading)
{
    <p><em>Loading tasks…</em></p>
}
else if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}
else
{
    <BoardStats TotalCount="@_allTasks.Count"
                ToDoCount="@CountByStatus("To Do")"
                InProgressCount="@CountByStatus("In Progress")"
                DoneCount="@CountByStatus("Done")"
                OverdueCount="@_allTasks.Count(t => t.DueDate.Date < DateTime.Today)" />

    <BoardSearchBar SearchTerm="@_searchTerm" SearchTermChanged="OnSearchChanged" />

    <div class="board-columns">
        @foreach (var col in _columns)
        {
            <BoardColumn ColumnName="@col"
                         Tasks="@FilteredTasksForStatus(col)"
                         CanMoveLeft="@(Array.IndexOf(_columns, col) > 0)"
                         CanMoveRight="@(Array.IndexOf(_columns, col) < _columns.Length - 1)"
                         OnMoveLeft="@(id => MoveTask(id, -1))"
                         OnMoveRight="@(id => MoveTask(id, 1))"
                         OnAddTask="@((args) => AddTask(col, args))" />
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];
    private List<TaskItem> _allTasks = new();
    private string _searchTerm = string.Empty;
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private int CountByStatus(string status) =>
        _allTasks.Count(t => t.Status == status);

    private List<TaskItem> FilteredTasksForStatus(string status) =>
        _allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(_searchTerm) ||
                         t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private void OnSearchChanged(string term) => _searchTerm = term;

    private async Task MoveTask(int taskId, int direction)
    {
        var task = _allTasks.FirstOrDefault(t => t.Id == taskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(_columns, task.Status);
        var newIndex = currentIndex + direction;
        if (newIndex < 0 || newIndex >= _columns.Length) return;

        var newStatus = _columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            // Update local state
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            _allTasks[idx] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask(string status, AddTaskArgs args)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            _allTasks.Add(created);
        }
        catch (Exception ex)
        {
            _error = $"Failed to create task: {ex.Message}";
        }
    }
}

.board-stats {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: #f0f0f0;
    border-radius: 6px;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.board-search {
    margin-bottom: 1rem;
}

.board-search input {
    width: 100%;
    max-width: 400px;
    padding: 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
}

.board-columns {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

::deep .board-column {
    flex: 1;
    background: #f8f9fa;
    border-radius: 8px;
    padding: 1rem;
    min-width: 250px;
}

::deep .board-column-header h3 {
    margin: 0 0 0.75rem;
}

::deep .board-task-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.75rem;
    margin-bottom: 0.5rem;
}

::deep .task-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

::deep .task-assignee {
    font-size: 0.875rem;
    color: #666;
}

::deep .task-priority {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: 600;
    margin: 0.25rem 0;
}

::deep .priority-high {
    background: #dc3545;
    color: #fff;
}

::deep .priority-medium {
    background: #ffc107;
    color: #000;
}

::deep .priority-low {
    background: #28a745;
    color: #fff;
}

::deep .task-due-date {
    font-size: 0.8rem;
    color: #888;
    margin-top: 0.25rem;
}

::deep .task-actions {
    display: flex;
    gap: 0.5rem;
    margin-top: 0.5rem;
}

::deep .btn-move {
    font-size: 0.75rem;
    padding: 0.2rem 0.5rem;
    border: 1px solid #adb5bd;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
}

::deep .btn-move:hover {
    background: #e9ecef;
}

::deep .btn-add-task {
    width: 100%;
    padding: 0.5rem;
    margin-top: 0.5rem;
    border: 2px dashed #adb5bd;
    border-radius: 6px;
    background: transparent;
    cursor: pointer;
    color: #666;
}

::deep .btn-add-task:hover {
    border-color: #666;
    color: #333;
}

::deep .board-add-task-form {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-top: 0.5rem;
    padding: 0.75rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
}

::deep .board-add-task-form input,
::deep .board-add-task-form select {
    padding: 0.4rem;
    border: 1px solid #ccc;
    border-radius: 4px;
}

::deep .form-actions {
    display: flex;
    gap: 0.5rem;
}

::deep .btn-save {
    padding: 0.4rem 1rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

::deep .btn-cancel {
    padding: 0.4rem 1rem;
    background: #6c757d;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

