toolArgs.file_text:
@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Project Board</h1>

@if (_loading)
{
    <p><em>Loading tasks…</em></p>
}
else if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}
else
{
    <BoardStats TotalCount="@_allTasks.Count"
                ToDoCount="@CountByStatus("To Do")"
                InProgressCount="@CountByStatus("In Progress")"
                DoneCount="@CountByStatus("Done")"
                OverdueCount="@_allTasks.Count(t => t.DueDate.Date < DateTime.Today)" />

    <BoardSearchBar SearchTerm="@_searchTerm" SearchTermChanged="OnSearchChanged" />

    <div class="board-columns">
        @foreach (var col in _columns)
        {
            <BoardColumn ColumnName="@col"
                         Tasks="@FilteredTasksForStatus(col)"
                         CanMoveLeft="@(Array.IndexOf(_columns, col) > 0)"
                         CanMoveRight="@(Array.IndexOf(_columns, col) < _columns.Length - 1)"
                         OnMoveLeft="@(id => MoveTask(id, -1))"
                         OnMoveRight="@(id => MoveTask(id, 1))"
                         OnAddTask="@((args) => AddTask(col, args))" />
        }
    </div>
}

@code {
    private readonly string[] _columns = ["To Do", "In Progress", "Done"];
    private List<TaskItem> _allTasks = new();
    private string _searchTerm = string.Empty;
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private int CountByStatus(string status) =>
        _allTasks.Count(t => t.Status == status);

    private List<TaskItem> FilteredTasksForStatus(string status) =>
        _allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(_searchTerm) ||
                         t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private void OnSearchChanged(string term) => _searchTerm = term;

    private async Task MoveTask(int taskId, int direction)
    {
        var task = _allTasks.FirstOrDefault(t => t.Id == taskId);
        if (task is null) return;

        var currentIndex = Array.IndexOf(_columns, task.Status);
        var newIndex = currentIndex + direction;
        if (newIndex < 0 || newIndex >= _columns.Length) return;

        var newStatus = _columns[newIndex];
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            // Update local state
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            _allTasks[idx] = task with { Status = newStatus };
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task AddTask(string status, AddTaskArgs args)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            _allTasks.Add(created);
        }
        catch (Exception ex)
        {
            _error = $"Failed to create task: {ex.Message}";
        }
    }
}

