toolArgs.file_text:
.board-stats {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: #f0f0f0;
    border-radius: 6px;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.board-search {
    margin-bottom: 1rem;
}

.board-search input {
    width: 100%;
    max-width: 400px;
    padding: 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
}

.board-columns {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

::deep .board-column {
    flex: 1;
    background: #f8f9fa;
    border-radius: 8px;
    padding: 1rem;
    min-width: 250px;
}

::deep .board-column-header h3 {
    margin: 0 0 0.75rem;
}

::deep .board-task-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.75rem;
    margin-bottom: 0.5rem;
}

::deep .task-title {
    font-weight: 600;
    margin-bottom: 0.25rem;
}

::deep .task-assignee {
    font-size: 0.875rem;
    color: #666;
}

::deep .task-priority {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: 600;
    margin: 0.25rem 0;
}

::deep .priority-high {
    background: #dc3545;
    color: #fff;
}

::deep .priority-medium {
    background: #ffc107;
    color: #000;
}

::deep .priority-low {
    background: #28a745;
    color: #fff;
}

::deep .task-due-date {
    font-size: 0.8rem;
    color: #888;
    margin-top: 0.25rem;
}

::deep .task-actions {
    display: flex;
    gap: 0.5rem;
    margin-top: 0.5rem;
}

::deep .btn-move {
    font-size: 0.75rem;
    padding: 0.2rem 0.5rem;
    border: 1px solid #adb5bd;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
}

::deep .btn-move:hover {
    background: #e9ecef;
}

::deep .btn-add-task {
    width: 100%;
    padding: 0.5rem;
    margin-top: 0.5rem;
    border: 2px dashed #adb5bd;
    border-radius: 6px;
    background: transparent;
    cursor: pointer;
    color: #666;
}

::deep .btn-add-task:hover {
    border-color: #666;
    color: #333;
}

::deep .board-add-task-form {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-top: 0.5rem;
    padding: 0.75rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
}

::deep .board-add-task-form input,
::deep .board-add-task-form select {
    padding: 0.4rem;
    border: 1px solid #ccc;
    border-radius: 4px;
}

::deep .form-actions {
    display: flex;
    gap: 0.5rem;
}

::deep .btn-save {
    padding: 0.4rem 1rem;
    background: #0d6efd;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

::deep .btn-cancel {
    padding: 0.4rem 1rem;
    background: #6c757d;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

